import{_ as r,c as d,o,a5 as t,j as a}from"./chunks/framework.Dtwt352Q.js";const _=JSON.parse('{"title":"v1.2.4：新增数据库检查命令、修复桌面端问题","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.2.4.md","filePath":"changelog/v1.2.4.md","lastUpdated":1772014034000}'),h={name:"changelog/v1.2.4.md"};function l(n,e,i,s,c,p){return o(),d("div",null,[...e[0]||(e[0]=[t('<h1 id="v1-2-4-新增数据库检查命令、修复桌面端问题" tabindex="-1">v1.2.4：新增数据库检查命令、修复桌面端问题 <a class="header-anchor" href="#v1-2-4-新增数据库检查命令、修复桌面端问题" aria-label="Permalink to “v1.2.4：新增数据库检查命令、修复桌面端问题”">​</a></h1><p><strong>发布日期</strong>：2026年2月15日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这次更新<strong>新增了数据库检查命令</strong>，方便排查问题，同时修复了桌面端的一些 Bug。</p><hr><h2 id="新功能-数据库检查命令" tabindex="-1">新功能：数据库检查命令 <a class="header-anchor" href="#新功能-数据库检查命令" aria-label="Permalink to “新功能：数据库检查命令”">​</a></h2><h3 id="这次更新了什么" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>新增了 <code>opencode db</code> 命令，可以直接查询和检查 OpenCode 的 SQLite 数据库。</p><h3 id="opencode-db-是什么" tabindex="-1">opencode db 是什么？ <a class="header-anchor" href="#opencode-db-是什么" aria-label="Permalink to “opencode db 是什么？”">​</a></h3><p>这是一个<strong>开发者工具</strong>，让你可以直接查看 OpenCode 的会话数据、文件记录等存储在数据库中的内容。</p><h3 id="什么时候用" tabindex="-1">什么时候用？ <a class="header-anchor" href="#什么时候用" aria-label="Permalink to “什么时候用？”">​</a></h3><p>当你遇到以下问题时，可以用它来排查：</p><table tabindex="0"><thead><tr><th>问题</th><th>用法</th></tr></thead><tbody><tr><td>会话找不到</td><td><code>opencode db &quot;SELECT * FROM sessions&quot;</code></td></tr><tr><td>文件记录异常</td><td><code>opencode db &quot;SELECT * FROM files&quot;</code></td></tr><tr><td>想看数据库结构</td><td><code>opencode db &quot;.schema&quot;</code></td></tr></tbody></table><p><strong>注意</strong>：普通用户一般不需要用这个命令，只有遇到数据问题时才用。</p><hr><h2 id="新功能-json-迁移改进" tabindex="-1">新功能：JSON 迁移改进 <a class="header-anchor" href="#新功能-json-迁移改进" aria-label="Permalink to “新功能：JSON 迁移改进”">​</a></h2><h3 id="这次更新了什么-1" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-1" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>在从 JSON 格式迁移到 SQLite 数据库时，所有 ID 都会从文件路径派生，确保一致性。</p><h3 id="这有什么好处" tabindex="-1">这有什么好处？ <a class="header-anchor" href="#这有什么好处" aria-label="Permalink to “这有什么好处？”">​</a></h3><p>保证数据迁移后的 ID 和原来的一致，避免出现数据关联错误。</p><hr><h2 id="问题修复-桌面端文件树崩溃" tabindex="-1">问题修复：桌面端文件树崩溃 <a class="header-anchor" href="#问题修复-桌面端文件树崩溃" aria-label="Permalink to “问题修复：桌面端文件树崩溃”">​</a></h2><h3 id="之前的问题" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题" aria-label="Permalink to “之前的问题”">​</a></h3><p>在桌面应用中，某些情况下打开文件树会导致程序崩溃。</p><h3 id="现在的情况" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况" aria-label="Permalink to “现在的情况”">​</a></h3><p>这个堆栈溢出问题已经修复，现在可以正常使用文件树了。</p><hr><h2 id="问题修复-通知清除" tabindex="-1">问题修复：通知清除 <a class="header-anchor" href="#问题修复-通知清除" aria-label="Permalink to “问题修复：通知清除”">​</a></h2><h3 id="之前的问题-1" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题-1" aria-label="Permalink to “之前的问题”">​</a></h3><p>桌面应用的通知一直堆积，无法清除。</p><h3 id="现在的情况-1" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况-1" aria-label="Permalink to “现在的情况”">​</a></h3><p>添加了&quot;清除通知&quot;操作，可以手动清空通知列表。</p><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>桌面端遇到过文件树崩溃</td><td>✅ 升级</td></tr><tr><td>想排查数据库问题</td><td>✅ 升级</td></tr><tr><td>用得好好的</td><td>可以等下次</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',37),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode upgrade")])],-1),t('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><h3 id="core-核心" tabindex="-1">Core（核心） <a class="header-anchor" href="#core-核心" aria-label="Permalink to “Core（核心）”">​</a></h3><ul><li>添加 db 命令用于数据库检查和查询</li><li>在 JSON 迁移期间从文件路径派生所有 ID</li></ul><h3 id="desktop-桌面应用" tabindex="-1">Desktop（桌面应用） <a class="header-anchor" href="#desktop-桌面应用" aria-label="Permalink to “Desktop（桌面应用）”">​</a></h3><ul><li>清除通知操作</li><li>修复文件树组件中的堆栈溢出问题</li></ul></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const m=r(h,[["render",l]]);export{_ as __pageData,m as default};
